data(mtcars)
head(mtcars)
# Write a Custom Summary Function
compute_stats &lt;- function(x) {
   if(!is.numeric(x)) {
     print("Sayısal Veri Girilmeli")
   }

   named_list &lt;- list(
     mean     = mean(x),
     median   = median(x),
     variance = var(x),
     iqr      = IQR(x),
     min      = min(x),
     max      = max(x)
   )

   return(named_list)
 }
compute_stats(mtcars$cyl)

